'use client';

import React, { useEffect, useState } from 'react';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { ScrollArea } from '@/components/ui/scroll-area';
import { ArrowLeft, ArrowRight } from 'lucide-react';
// import axios from 'axios';

interface Order {
  id: string;
  customer: string;
  total: number;
  status: 'Pending' | 'Shipped' | 'Delivered';
  date: string;
}

export default function OrdersPage() {
  const [orders, setOrders] = useState<Order[]>([]);
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(3); // dummy value
  const limit = 5;

  useEffect(() => {
    // 🟢 Dummy data
    const dummyOrders: Order[] = [
      { id: 'ORD-1001', customer: 'Priya Sharma', total: 45, status: 'Pending', date: '2025-11-01' },
      { id: 'ORD-1002', customer: 'Amit Verma', total: 90, status: 'Shipped', date: '2025-11-03' },
      { id: 'ORD-1003', customer: 'Rina Das', total: 30, status: 'Delivered', date: '2025-11-06' },
      { id: 'ORD-1004', customer: 'Rohit Singh', total: 60, status: 'Pending', date: '2025-11-08' },
      { id: 'ORD-1005', customer: 'Anita Kapoor', total: 75, status: 'Shipped', date: '2025-11-10' },
    ];
    setOrders(dummyOrders);

    // 🟢 Replace with API call
    // const token = localStorage.getItem('token');
    // axios.get(`/api/orders?page=${page}&limit=${limit}`, { headers: { Authorization: `Bearer ${token}` } })
    //   .then(res => {
    //     setOrders(res.data.orders);
    //     setTotalPages(res.data.totalPages);
    //   });
  }, [page]);

  const nextPage = () => { if (page < totalPages) setPage(p => p + 1); };
  const prevPage = () => { if (page > 1) setPage(p => p - 1); };

  return (
    <div className="p-6 space-y-6">
      <h1 className="text-2xl font-bold mb-4">📦 Orders</h1>

      <Card>
        <CardContent>
          <ScrollArea className="max-h-[500px]">
            <table className="w-full table-auto border-collapse">
              <thead className="bg-gray-100">
                <tr>
                  <th className="p-2 text-left">Order ID</th>
                  <th className="p-2 text-left">Customer</th>
                  <th className="p-2 text-left">Date</th>
                  <th className="p-2 text-left">Total</th>
                  <th className="p-2 text-left">Status</th>
                  <th className="p-2 text-left">Action</th>
                </tr>
              </thead>
              <tbody>
                {orders.map(order => (
                  <tr key={order.id} className="border-t hover:bg-gray-50">
                    <td className="p-2">{order.id}</td>
                    <td className="p-2">{order.customer}</td>
                    <td className="p-2">{order.date}</td>
                    <td className="p-2">₹ {order.total}</td>
                    <td className="p-2">
                      <span className={`px-2 py-1 rounded-full text-xs font-medium ${
                        order.status === 'Pending' ? 'bg-yellow-100 text-yellow-800' :
                        order.status === 'Shipped' ? 'bg-blue-100 text-blue-800' :
                        'bg-green-100 text-green-800'
                      }`}>
                        {order.status}
                      </span>
                    </td>
                    <td className="p-2 flex gap-2">
                      <Button size="sm" className="bg-blue-600 hover:bg-blue-700 text-white">
                        View
                      </Button>
                      <Button size="sm" className="bg-green-600 hover:bg-green-700 text-white">
                        Update
                      </Button>
                      <Button size="sm" className="bg-red-600 hover:bg-red-700 text-white">
                        Delete
                      </Button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </ScrollArea>
        </CardContent>
      </Card>

      {/* Pagination */}
      <div className="flex justify-center items-center gap-3 mt-4">
        <Button variant="outline" onClick={prevPage} disabled={page === 1}>
          <ArrowLeft className="mr-1 w-4 h-4" /> Prev
        </Button>
        {[...Array(totalPages)].map((_, idx) => (
          <Button
            key={idx}
            variant={page === idx + 1 ? 'default' : 'outline'}
            onClick={() => setPage(idx + 1)}
          >
            {idx + 1}
          </Button>
        ))}
        <Button variant="outline" onClick={nextPage} disabled={page === totalPages}>
          Next <ArrowRight className="ml-1 w-4 h-4" />
        </Button>
      </div>
    </div>
  );
}
